import { NextRequest, NextResponse } from "next/server";
import { writeFile } from "fs/promises";
import path from "path";
import fs from "fs/promises";
import { PdfReader } from "pdfreader";

const uploadDir = path.join(process.cwd(), "public", "uploads");

async function ensureUploadDir() {
  try {
    await fs.access(uploadDir);
  } catch {
    await fs.mkdir(uploadDir, { recursive: true });
  }
}

function extractTextFromPDF(buffer: Buffer): Promise<string> {
  return new Promise((resolve, reject) => {
    const reader = new PdfReader();
    let text = "";

    reader.parseBuffer(buffer, (err, item) => {
      if (err) {
        reject(err);
      } else if (!item) {
        resolve(text.trim()); // End of file
      } else if (item.text) {
        text += item.text + " ";
      }
    });
  });
}

// Function to detect if the text contains marksheet-like data
function isMarksheet(text: string): boolean {
  const lowerText = text.toLowerCase();

  // Common marksheet keywords
  const keywords = [
    "marks",
    "percentage",
    "subject",
    "total",
    "obtained",
    "grade",
    "score",
    "result",
    "cgpa",
    "sgpa",
    "gpa",
    "pass",
    "fail",
  ];

  // Check if at least 3 keywords appear in the text
  const keywordCount = keywords.filter((keyword) =>
    lowerText.includes(keyword)
  ).length;

  // Regular expressions for numeric patterns related to marks
  const percentagePattern = /\b\d{1,3}\.\d{1,2}%\b/; // Matches percentages like "85.5%"
  const marksPattern = /\b\d{1,3}\/\d{1,3}\b/; // Matches marks like "45/50"

  return (
    keywordCount >= 3 ||
    percentagePattern.test(lowerText) ||
    marksPattern.test(lowerText)
  );
}

export async function POST(req: NextRequest) {
  try {
    await ensureUploadDir();
    const contentType = req.headers.get("content-type") || "";

    if (!contentType.includes("multipart/form-data")) {
      return NextResponse.json(
        { message: "Invalid content type" },
        { status: 400 }
      );
    }

    const formData = await req.formData();
    const file = formData.get("file");

    if (!file || !(file instanceof File)) {
      return NextResponse.json(
        { message: "No file provided" },
        { status: 400 }
      );
    }

    if (file.size === 0) {
      return NextResponse.json(
        { message: "Uploaded file is empty" },
        { status: 400 }
      );
    }

    const bytes = await file.arrayBuffer();
    const buffer = Buffer.from(bytes);
    const uniqueFilename = `${Date.now()}-${file.name}`;
    const filepath = path.join(uploadDir, uniqueFilename);

    await writeFile(filepath, buffer);

    try {
      const extractedText = await extractTextFromPDF(buffer);
      const marksheetDetected = isMarksheet(extractedText);

      return NextResponse.json({
        text: extractedText,
        filename: uniqueFilename,
        isMarksheet: marksheetDetected
          ? "Yes, this appears to be a marksheet."
          : "No, this does not appear to be a marksheet.",
      });
    } catch (error) {
      console.error("Error extracting text:", error);
      return NextResponse.json(
        { message: "Failed to extract text" },
        { status: 400 }
      );
    }
  } catch (error) {
    console.error("Error processing file:", error);
    return NextResponse.json(
      { message: "Error processing file" },
      { status: 500 }
    );
  }
}
